mapper.select:
SELECT TIME as time, PARTITION_NAME as partitionName, round(avgMerge(USED_AVG),2) as used, round(avgMerge(UTILIZATION_AVG),2) as utilization, round(avgMerge(SIZE_AVG),2) as size, DOMAIN_ID as domainId FROM AGG_DOMAIN_PARTITION_DETAIL_1H WHERE TIME BETWEEN ${startTime} AND ${endTime}
AND DOMAIN_ID=${domainId}
GROUP BY DOMAIN_ID, PARTITION_NAME, TIME ORDER BY TIME ASC
